(function(){var API="https://flotadsp-backend.fly.dev/api";function tok(){return localStorage.getItem("flotadsp_token")||"";}function call(path,body){return fetch(API+path,{method:"POST",headers:{"Content-Type":"application/json","Authorization":"Bearer "+tok()},body:JSON.stringify(body)}).then(function(r){return r.json().then(function(j){return{ok:r.ok,j:j};});});}
window.__fdspBags=function(id,mode){if(mode==="set"){var n=prompt("¿Cuántas bolsas tiene ahora esta furgoneta? (stock total)");if(n===null)return;call("/vehicles/"+id+"/bags/set",{bags:parseInt(n)||0}).then(function(res){if(res.ok){alert("Stock fijado en "+res.j.bags_remaining+" bolsas. Recarga la página para ver el cambio.");location.reload();}else alert("Error: "+(res.j.detail||"no se pudo"));});}else{var u=prompt("¿Cuántas bolsas se han gastado?","1");if(u===null)return;call("/vehicles/"+id+"/bags/consume",{used:parseInt(u)||1}).then(function(res){if(res.ok){alert("Gastadas. Quedan "+res.j.bags_remaining+" bolsas.");location.reload();}else alert("Error: "+(res.j.detail||"no se pudo"));});}};
window.__fdspKm=function(id){var k=prompt("Kilómetros actuales de la furgoneta:");if(k===null)return;call("/vehicles/"+id+"/mileage",{km:parseInt(k)||0}).then(function(res){if(res.ok){var msg="Kilómetros actualizados a "+res.j.mileage.toLocaleString()+" km.";if(res.j.oil_alert)msg+="\n\n⚠️ "+res.j.oil_alert.message;alert(msg);location.reload();}else alert("Error: "+(res.j.detail||"no se pudo"));});};
window.__fdspOil=function(id){var k=prompt("¿A cuántos kilómetros se ha hecho el cambio de aceite?\n(pon los km actuales del vehículo)");if(k===null)return;var iv=prompt("¿Cada cuántos km toca cambiarlo?","15000");if(iv===null)return;var wb=prompt("¿Cuántos km antes quieres el aviso?","2500");if(wb===null)return;call("/vehicles/"+id+"/oil/change",{km:parseInt(k)||0,interval_km:parseInt(iv)||15000,warning_before_km:parseInt(wb)||2500}).then(function(res){if(res.ok){alert("Cambio de aceite registrado.\nPróximo cambio a los "+res.j.next_change_km.toLocaleString()+" km.\nAviso al llegar a "+res.j.warning_at_km.toLocaleString()+" km.");location.reload();}else alert("Error: "+(res.j.detail||"no se pudo"));});};
window.__fdspMaint=function(id,kind,label){var k=prompt("¿A cuántos km se ha hecho el cambio? ("+label+")");if(k===null)return;var iv=prompt("¿Cada cuántos km toca repetirlo?",kind==="ruedas"?"40000":"30000");if(iv===null)return;var wb=prompt("¿Cuántos km antes quieres el aviso?","3000");if(wb===null)return;call("/vehicles/"+id+"/maintenance/"+kind+"/change",{km:parseInt(k)||0,interval_km:parseInt(iv)||0,warning_before_km:parseInt(wb)||3000}).then(function(res){if(res.ok){alert(label+" registrado.\nPróximo a los "+res.j.next_change_km.toLocaleString()+" km.");location.reload();}else alert("Error: "+(res.j.detail||"no se pudo"));});};
})();
