function FdspHist(){
  const [vehicles,setVehicles]=k.useState([]);
  const [sel,setSel]=k.useState("");
  const [hist,setHist]=k.useState(null);
  const [loading,setLoading]=k.useState(false);
  const kmRef=k.useRef(null), bagsRef=k.useRef(null);
  const charts=k.useRef({});
  // Cargar Chart.js una vez
  k.useEffect(()=>{
    if(!window.Chart){
      const sc=document.createElement("script");
      sc.src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js";
      document.head.appendChild(sc);
    }
    xe.get("/vehicles").then(r=>{
      const vs=(r.data||[]).slice().sort((a,b)=>(a.license_plate||"").localeCompare(b.license_plate||""));
      setVehicles(vs);
      if(vs.length){setSel(vs[0].id);}
    }).catch(()=>{});
  },[]);
  k.useEffect(()=>{
    if(!sel)return;
    setLoading(true);
    xe.get("/vehicles/"+sel+"/history").then(r=>{setHist(r.data);setLoading(false);}).catch(()=>{setHist(null);setLoading(false);});
  },[sel]);
  k.useEffect(()=>{
    if(!hist)return;
    const draw=()=>{
      if(!window.Chart){setTimeout(draw,300);return;}
      const C=window.Chart;
      ["km","bags"].forEach(key=>{if(charts.current[key]){charts.current[key].destroy();charts.current[key]=null;}});
      const opt=(unit)=>({responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:{backgroundColor:"#1a1e25",borderColor:"#262b33",borderWidth:1,padding:10,callbacks:{label:(c)=>c.parsed.y.toLocaleString()+" "+unit}}},scales:{x:{grid:{color:"#1e232b"},ticks:{color:"#5f6671",font:{size:11}}},y:{grid:{color:"#1e232b"},ticks:{color:"#5f6671",font:{size:11}}}}});
      const km=hist.km_history||[];
      if(kmRef.current&&km.length>1){
        charts.current.km=new C(kmRef.current,{type:"line",data:{labels:km.map(p=>p.date),datasets:[{data:km.map(p=>p.km),borderColor:"#ff6b1a",backgroundColor:"rgba(255,107,26,.12)",fill:true,tension:.3,pointRadius:4,pointBackgroundColor:"#ff6b1a",borderWidth:2}]},options:opt("km")});
      }
      const bg=hist.bags_history||[];
      if(bagsRef.current&&bg.length>0){
        charts.current.bags=new C(bagsRef.current,{type:"line",data:{labels:bg.map(p=>p.date),datasets:[{data:bg.map(p=>p.remaining),borderColor:"#5fb336",backgroundColor:"rgba(95,179,54,.12)",fill:true,tension:.2,pointRadius:4,pointBackgroundColor:"#5fb336",borderWidth:2}]},options:opt("bolsas")});
      }
    };
    setTimeout(draw,100);
  },[hist]);
  const km=hist&&hist.km_history||[], bg=hist&&hist.bags_history||[];
  return d.jsxs("div",{children:[
    d.jsx(xr,{title:"Histórico de flota",desc:"Evolución de kilómetros y consumo de bolsas por furgoneta"}),
    d.jsx("div",{className:"mb-4",children:d.jsxs("div",{className:"flex flex-col gap-1",children:[
      d.jsx("label",{className:"text-xs text-dark-400 uppercase tracking-wider",children:"Furgoneta"}),
      d.jsx("select",{className:"input max-w-md",value:sel,onChange:e=>setSel(e.target.value),children:vehicles.map(v=>d.jsx("option",{value:v.id,children:v.license_plate+" — "+(v.brand||"")+" "+(v.model||"")},v.id))})
    ]})}),
    loading?d.jsx("div",{className:"text-center text-dark-500 py-10",children:"Cargando…"}):hist?d.jsxs("div",{children:[
      d.jsxs("div",{className:"grid grid-cols-2 md:grid-cols-4 gap-3 mb-5",children:[
        d.jsxs("div",{className:"card p-4",children:[d.jsx("div",{className:"text-xs text-dark-400 uppercase",children:"Km actuales"}),d.jsxs("div",{className:"text-2xl font-bold",children:[(hist.current_mileage||0).toLocaleString()," ",d.jsx("span",{className:"text-sm text-dark-400",children:"km"})]})]}),
        d.jsxs("div",{className:"card p-4",children:[d.jsx("div",{className:"text-xs text-dark-400 uppercase",children:"Bolsas stock"}),d.jsx("div",{className:"text-2xl font-bold",children:hist.current_bags||0})]}),
        d.jsxs("div",{className:"card p-4",children:[d.jsx("div",{className:"text-xs text-dark-400 uppercase",children:"Registros km"}),d.jsx("div",{className:"text-2xl font-bold",children:km.length})]}),
        d.jsxs("div",{className:"card p-4",children:[d.jsx("div",{className:"text-xs text-dark-400 uppercase",children:"Mov. bolsas"}),d.jsx("div",{className:"text-2xl font-bold",children:bg.length})]})
      ]}),
      d.jsxs("div",{className:"card p-5 mb-4",children:[
        d.jsx("h3",{className:"font-semibold mb-1",children:"Evolución de kilómetros"}),
        d.jsx("p",{className:"text-xs text-dark-400 mb-4",children:"Kilometraje registrado en cada actualización"}),
        km.length>1?d.jsx("div",{style:{position:"relative",height:"260px"},children:d.jsx("canvas",{ref:kmRef})}):d.jsx("div",{className:"text-center text-dark-500 py-8 text-sm",children:"Aún no hay suficientes registros de km. Se acumularán con cada actualización del conductor."})
      ]}),
      d.jsxs("div",{className:"card p-5",children:[
        d.jsx("h3",{className:"font-semibold mb-1",children:"Consumo de bolsas"}),
        d.jsx("p",{className:"text-xs text-dark-400 mb-4",children:"Stock de bolsas tras cada movimiento"}),
        bg.length>0?d.jsx("div",{style:{position:"relative",height:"260px"},children:d.jsx("canvas",{ref:bagsRef})}):d.jsx("div",{className:"text-center text-dark-500 py-8 text-sm",children:"Aún no hay movimientos de bolsas registrados."})
      ]})
    ]}):d.jsx("div",{className:"text-center text-dark-500 py-10",children:"Selecciona una furgoneta"})
  ]});
}


